SUPPORTED_EXTS = {".txt", ".md", ".markdown", ".rst", ".log", ".csv", ".json", ".yaml", ".yml", ".html", ".htm"}


def _now_iso() -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())


def _sha256_text(s: str) -> str:
    return hashlib.sha256(s.encode("utf-8", errors="ignore")).hexdigest()


def _safe_read_text(path: str, max_bytes: int = 10_000_000) -> str:
    with open(path, "rb") as f:
        data = f.read(max_bytes + 1)
    if len(data) > max_bytes:
        data = data[:max_bytes]
    for enc in ("utf-8", "utf-8-sig", "cp1252", "latin-1"):
        try:
            return data.decode(enc)
        except Exception:
            continue
    return data.decode("utf-8", errors="ignore")


def _is_text_file(path: str) -> bool:
    ext = os.path.splitext(path)[1].lower()
    return ext in SUPPORTED_EXTS


def _walk_files(root: str) -> List[str]:
    files = []
    for dirpath, _, filenames in os.walk(root):
        for fn in filenames:
            p = os.path.join(dirpath, fn)
            if _is_text_file(p):
                files.append(p)
    return sorted(files)


def _normalize_whitespace(s: str) -> str:
    return " ".join(s.replace("\r\n", "\n").replace("\r", "\n").split())


def chunk_text(text: str, chunk_size: int = 1200, chunk_overlap: int = 200) -> List[str]:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    if not text.strip():
        return []
    paragraphs = [p.strip() for p in text.split("\n\n") if p.strip()]
    chunks = []
    cur = ""
    for p in paragraphs:
        if not cur:
            cur = p
            continue
        if len(cur) + 2 + len(p) <= chunk_size:
            cur = cur + "\n\n" + p
        else:
            chunks.append(cur)
            if chunk_overlap > 0 and len(cur) > chunk_overlap:
                tail = cur[-chunk_overlap:]
                cur = tail + "\n\n" + p
            else:
                cur = p
    if cur:
        chunks.append(cur)

    final_chunks = []
    for c in chunks:
        c = c.strip()
        if len(c) <= chunk_size:
            final_chunks.append(c)
        else:
            start = 0
            while start < len(c):
                end = min(len(c), start + chunk_size)
                final_chunks.append(c[start:end].strip())
                if end == len(c):
                    break
                start = max(0, end - chunk_overlap)
    return [x for x in final_chunks if x.strip()]


@dataclass
class RetrievedDoc:
    id: str
    text: str
    metadata: Dict[str, Any]
    distance: float


class RAGSystem:
    def __init__(
        self,
        persist_dir: str = "./rag_chroma",
        collection_name: str = "company_kb",
        embedding_model: str = "sentence-transformers/all-MiniLM-L6-v2",
        openai_model: str = "gpt-4o-mini",
        openai_api_key: Optional[str] = None,
    ):
        self.persist_dir = persist_dir
        self.collection_name = collection_name
        self.embedding_model_name = embedding_model
        self.openai_model = openai_model

        os.makedirs(self.persist_dir, exist_ok=True)

        self.client = chromadb.PersistentClient(
            path=self.persist_dir,
            settings=Settings(anonymized_telemetry=False),
        )

        self.collection = self.client.get_or_create_collection(
            name=self.collection_name,
            metadata={"created_at": _now_iso(), "embedding_model": self.embedding_model_name},
        )

        self.embedder = SentenceTransformer(self.embedding_model_name)

        api_key = openai_api_key or os.environ.get("OPENAI_API_KEY")
        if not api_key:
            raise RuntimeError("OPENAI_API_KEY is not set. Provide via env var or openai_api_key parameter.")
        self.llm = OpenAI(api_key=api_key)

    def _embed_texts(self, texts: List[str]) -> List[List[float]]:
        if not texts:
            return []
        vecs = self.embedder.encode(texts, normalize_embeddings=True, show_progress_bar=False)
        if isinstance(vecs, np.ndarray):
            vecs = vecs.tolist()
        return vecs

    def _make_chunk_id(self, source_path: str, chunk_index: int, chunk_text: str) -> str:
        base = f"{os.path.abspath(source_path)}::{chunk_index}::{_sha256_text(chunk_text)[:16]}"
        return _sha256_text(base)

    def index_directory(
        self,
        docs_dir: str,
        chunk_size: int = 1200,
        chunk_overlap: int = 200,
        batch_size: int = 64,
        skip_if_unchanged: bool = True,
        max_file_bytes: int = 10_000_000,
    ) -> Dict[str, Any]:
        docs_dir = os.path.abspath(docs_dir)
        files = _walk_files(docs_dir)

        indexed_chunks = 0
        skipped_files = 0
        processed_files = 0

        to_add_ids = []
        to_add_docs = []
        to_add_metas = []

        for path in files:
            processed_files += 1
            try:
                raw = _safe_read_text(path, max_bytes=max_file_bytes)
            except Exception:
                continue

            raw_norm = _normalize_whitespace(raw)
            if not raw_norm:
                continue

            file_hash = _sha256_text(raw_norm)
            rel_path = os.path.relpath(path, docs_dir)

            if skip_if_unchanged:
                try:
                    existing = self.collection.get(
                        where={"source_relpath": rel_path, "source_hash": file_hash},
                        include=["ids"],
                        limit=1,
                    )
                    if existing and existing.get("ids"):
                        skipped_files += 1
                        continue
                except Exception:
                    pass

            chunks = chunk_text(raw, chunk_size=chunk_size, chunk_overlap=chunk_overlap)
            if not chunks:
                continue

            for i, ch in enumerate(chunks):
                cid = self._make_chunk_id(path, i, ch)
                meta = {
                    "source_path": os.path.abspath(path),
                    "source_relpath": rel_path,
                    "source_hash": file_hash,
                    "chunk_index": i,
                    "chunk_count": len(chunks),
                    "indexed_at": _now_iso(),
                }
                to_add_ids.append(cid)
                to_add_docs.append(ch)
                to_add_metas.append(meta)

                if len(to_add_ids) >= batch_size:
                    indexed_chunks += self._flush_add(to_add_ids, to_add_docs, to_add_metas)
                    to_add_ids, to_add_docs, to_add_metas = [], [], []

        if to_add_ids:
            indexed_chunks += self._flush_add(to_add_ids, to_add_docs, to_add_metas)

        return {
            "docs_dir": docs_dir,
            "files_found": len(files),
            "files_processed": processed_files,
            "files_skipped_unchanged": skipped_files,
            "chunks_indexed": indexed_chunks,
            "collection_name": self.collection_name,
            "persist_dir": self.persist_dir,
        }

    def _flush_add(self, ids: List[str], docs: List[str], metas: List[Dict[str, Any]]) -> int:
        embeddings = self._embed_texts(docs)
        try:
            self.collection.add(ids=ids, documents=docs, metadatas=metas, embeddings=embeddings)
            return len(ids)
        except Exception:
            existing = set()
            try:
                got = self.collection.get(ids=ids, include=["ids"])
                existing = set(got.get("ids", []) or [])
            except Exception:
                existing = set()

            new_ids, new_docs, new_metas, new_embs = [], [], [], []
            for i, cid in enumerate(ids):
                if cid in existing:
                    continue
                new_ids.append(cid)
                new_docs.append(docs[i])
                new_metas.append(metas[i])
                new_embs.append(embeddings[i])

            if new_ids:
                self.collection.add(ids=new_ids, documents=new_docs, metadatas=new_metas, embeddings=new_embs)
            return len(new_ids)

    def retrieve(
        self,
        query: str,
        top_k: int = 8,
        where: Optional[Dict[str, Any]] = None,
    ) -> List[RetrievedDoc]:
        q = query.strip()
        if not q:
            return []
        q_emb = self._embed_texts([q])[0]
        res = self.collection.query(
            query_embeddings=[q_emb],
            n_results=top_k,
            where=where,
            include=["documents", "metadatas", "distances", "ids"],
        )
        ids = (res.get("ids") or [[]])[0]
        docs = (res.get("documents") or [[]])[0]
        metas = (res.get("metadatas") or [[]])[0]
        dists = (res.get("distances") or [[]])[0]
        out = []
        for i in range(len(ids)):
            out.append(RetrievedDoc(id=ids[i], text=docs[i], metadata=metas[i], distance=float(dists[i])))
        return out

    def build_prompt(
        self,
        query: str,
        retrieved: List[RetrievedDoc],
        system_instructions: Optional[str] = None,
    ) -> List[Dict[str, str]]:
        sys_msg = system_instructions or (
            "You are an internal company knowledge base assistant. "
            "Use ONLY the provided context to answer. "
            "If the answer is not in the context, say you don't know and ask a clarifying question if helpful. "
            "Cite sources by referencing [source_relpath#chunk_index]."
        )

        context_blocks = []
        for d in retrieved:
            rel = d.metadata.get("source_relpath", d.metadata.get("source_path", "unknown"))
            idx = d.metadata.get("chunk_index", "NA")
            header = f"[{rel}#{idx}]"
            context_blocks.append(f"{header}\n{d.text}")

        context = "\n\n---\n\n".join(context_blocks) if context_blocks else "(no retrieved context)"

        user_msg = (
            "CONTEXT (all retrieved documents):\n"
            f"{context}\n\n"
            "USER QUESTION:\n"
            f"{query}\n\n"
            "INSTRUCTIONS:\n"
            "- Answer using the context above.\n"
            "- If multiple documents conflict, explain the discrepancy and cite both.\n"
            "- Provide concise, actionable answers.\n"
        )

        return [
            {"role": "system", "content": sys_msg},
            {"role": "user", "content": user_msg},
        ]

    def generate(
        self,
        query: str,
        top_k: int = 8,
        where: Optional[Dict[str, Any]] = None,
        system_instructions: Optional[str] = None,
        temperature: float = 0.2,
        max_output_tokens: int = 700,
    ) -> Dict[str, Any]:
        retrieved = self.retrieve(query, top_k=top_k, where=where)
        messages = self.build_prompt(query, retrieved, system_instructions=system_instructions)

        resp = self.llm.chat.completions.create(
            model=self.openai_model,
            messages=messages,
            temperature=temperature,
            max_tokens=max_output_tokens,
        )

        answer = resp.choices[0].message.content if resp and resp.choices else ""
        return {
            "query": query,
            "answer": answer,
            "retrieved": [
                {
                    "id": d.id,
                    "distance": d.distance,
                    "metadata": d.metadata,
                    "text": d.text,
                }
                for d in retrieved
            ],
            "model": self.openai_model,
        }


def _print_json(obj: Any) -> None:
    print(json.dumps(obj, ensure_ascii=False, indent=2))


def main():
    parser = argparse.ArgumentParser(description="Internal KB RAG chatbot (Chroma + SentenceTransformers + OpenAI).")
    parser.add_argument("--persist-dir", default=os.environ.get("RAG_PERSIST_DIR", "./rag_chroma"))
    parser.add_argument("--collection", default=os.environ.get("RAG_COLLECTION", "company_kb"))
    parser.add_argument("--embed-model", default=os.environ.get("RAG_EMBED_MODEL", "sentence-transformers/all-MiniLM-L6-v2"))
    parser.add_argument("--llm-model", default=os.environ.get("RAG_LLM_MODEL", "gpt-4o-mini"))
    sub = parser.add_subparsers(dest="cmd", required=True)

    p_index = sub.add_parser("index", help="Index documents from a directory.")
    p_index.add_argument("--docs-dir", required=True)
    p_index.add_argument("--chunk-size", type=int, default=1200)
    p_index.add_argument("--chunk-overlap", type=int, default=200)
    p_index.add_argument("--batch-size", type=int, default=64)
    p_index.add_argument("--no-skip-unchanged", action="store_true")
    p_index.add_argument("--max-file-bytes", type=int, default=10_000_000)

    p_ask = sub.add_parser("ask", help="Ask a question (one-shot).")
    p_ask.add_argument("--query", required=True)
    p_ask.add_argument("--top-k", type=int, default=8)
    p_ask.add_argument("--temperature", type=float, default=0.2)
    p_ask.add_argument("--max-output-tokens", type=int, default=700)
    p_ask.add_argument("--where", default=None, help='Optional JSON filter for Chroma "where".')

    p_chat = sub.add_parser("chat", help="Interactive chat loop (stateless per turn).")
    p_chat.add_argument("--top-k", type=int, default=8)
    p_chat.add_argument("--temperature", type=float, default=0.2)
    p_chat.add_argument("--max-output-tokens", type=int, default=700)
    p_chat.add_argument("--where", default=None, help='Optional JSON filter for Chroma "where".')

    args = parser.parse_args()

    rag = RAGSystem(
        persist_dir=args.persist_dir,
        collection_name=args.collection,
        embedding_model=args.embed_model,
        openai_model=args.llm_model,
    )

    if args.cmd == "index":
        stats = rag.index_directory(
            docs_dir=args.docs_dir,
            chunk_size=args.chunk_size,
            chunk_overlap=args.chunk_overlap,
            batch_size=args.batch_size,
            skip_if_unchanged=not args.no_skip_unchanged,
            max_file_bytes=args.max_file_bytes,
        )
        _print_json(stats)
        return

    where = None
    if getattr(args, "where", None):
        try:
            where = json.loads(args.where)
        except Exception as e:
            raise SystemExit(f"Invalid --where JSON: {e}")

    if args.cmd == "ask":
        out = rag.generate(
            query=args.query,
            top_k=args.top_k,
            where=where,
            temperature=args.temperature,
            max_output_tokens=args.max_output_tokens,
        )
        _print_json(out)
        return

    if args.cmd == "chat":
        print("Internal KB Chat (Ctrl+C to exit).")
        while True:
            try:
                q = input("\nYou> ").strip()
            except (KeyboardInterrupt, EOFError):
                print("\nBye.")
                return
            if not q:
                continue
            out = rag.generate(
                query=q,
                top_k=args.top_k,
                where=where,
                temperature=args.temperature,
                max_output_tokens=args.max_output_tokens,
            )
            print("\nAssistant>\n" + (out.get("answer") or "").strip())
            print("\nRetrieved:")
            for d in out.get("retrieved", []):
                meta = d.get("metadata", {}) or {}
                rel = meta.get("source_relpath", meta.get("source_path", "unknown"))
                idx = meta.get("chunk_index", "NA")
                dist = d.get("distance", None)
                print(f"- [{rel}#{idx}] distance={dist}")
        return


if __name__ == "__main__":
    main()